using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ---------------------------------------------------------------------------
// DI & chat client setup
// ---------------------------------------------------------------------------
var services = new ServiceCollection();

services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, apiKey: apiKey));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook = new ResearchNotebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to find information about")] string query) =>
        {
            return WebSearchTool.SearchAsync(query);
        },
        new AIFunctionFactoryOptions
        {
            Name = "web_search",
            Description = "Search the web for current information on a topic. Returns a list of results with titles, snippets, and URLs.",
        }),

    AIFunctionFactory.Create(
        (
            [Description("Short title for this note")] string title,
            [Description("The content/findings to save")] string content
        ) =>
        {
            notebook.AddNote(title, content);
            return $"Note saved: '{title}' ({content.Length} chars)";
        },
        new AIFunctionFactoryOptions
        {
            Name = "take_note",
            Description = "Save a research finding or key insight to the notebook for later summarization.",
        }),

    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        new AIFunctionFactoryOptions
        {
            Name = "read_notes",
            Description = "Retrieve all notes taken so far during the research session.",
        }),
};

// ---------------------------------------------------------------------------
// Agent
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    },
    loggerFactory,
    sp);

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

var session = await agent.CreateSessionAsync();

var prompt = $"""
    Research the following topic thoroughly: "{topic}"

    Follow these steps:
    1. Search the web for information about this topic (perform 2-3 different searches
       with varied queries to get broad coverage).
    2. For each useful finding, use the take_note tool to save key insights.
    3. After gathering enough information, read your notes back with read_notes.
    4. Provide a well-structured final summary that synthesizes all your findings.
       Include key facts, different perspectives, and cite sources where possible.
    """;

var response = await agent.RunAsync(prompt, session);

Console.WriteLine();
Console.WriteLine("═══════════ Research Summary ═══════════");
Console.WriteLine(response.Text);
Console.WriteLine("════════════════════════════════════════");
Console.WriteLine();
Console.WriteLine($"Notes collected: {notebook.Count}");

if (response.Usage is { } usage)
{
    Console.WriteLine($"Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}, total: {usage.TotalTokenCount}");
}

// ---------------------------------------------------------------------------
// Simulated web search tool
// ---------------------------------------------------------------------------
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(10),
    };

    public static async Task<string> SearchAsync(string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);

            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("Abstract", out var abstractText)
                && abstractText.GetString() is { Length: > 0 } abs)
            {
                var source = root.TryGetProperty("AbstractSource", out var src)
                    ? src.GetString() : "Unknown";
                var absUrl = root.TryGetProperty("AbstractURL", out var u)
                    ? u.GetString() : "";
                results.Add($"[{source}] {abs} ({absUrl})");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text)
                        && text.GetString() is { Length: > 0 } t)
                    {
                        var firstUrl = item.TryGetProperty("FirstURL", out var fu)
                            ? fu.GetString() : "";
                        results.Add($"- {t} ({firstUrl})");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No detailed results found for '{query}'. Try a more specific query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

// ---------------------------------------------------------------------------
// Research notebook
// ---------------------------------------------------------------------------
class ResearchNotebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public int Count => _notes.Count;

    public void AddNote(string title, string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
    }

    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes taken yet.";
        }

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"[Note {i + 1}] {n.Title}\n{n.Content}"));
    }
}

